// ============================================================
// PROMO DASHBOARD DAILY CHECKER
// ============================================================

const inputData = $input.first().json;
const sha = inputData.sha;

// Decode HTML from GitHub base64
const html = Buffer.from(inputData.content.replace(/\n/g, ''), 'base64').toString('utf8');
const today = new Date().toLocaleDateString('en-GB');

// ---- Extract BRANDS array ----
const brandsStartMarker = 'const BRANDS = [';
const brandsStart = html.indexOf(brandsStartMarker);
if (brandsStart === -1) throw new Error('Could not find BRANDS array in HTML');

let depth = 0;
let pos = brandsStart + brandsStartMarker.length - 1;
let brandsEnd = -1;
for (; pos < html.length; pos++) {
  if (html[pos] === '[') depth++;
  if (html[pos] === ']') {
    depth--;
    if (depth === 0) { brandsEnd = pos + 1; break; }
  }
}
if (brandsEnd === -1) throw new Error('Could not find end of BRANDS array');

const brandsCode = html.slice(brandsStart + brandsStartMarker.length, brandsEnd - 1);
let brands = [];
brands = new Function('return [' + brandsCode + ']')();

// ---- UK headers ----
const UK_HEADERS = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36',
  'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
  'Accept-Language': 'en-GB,en;q=0.9',
  'Cache-Control': 'no-cache',
  'Pragma': 'no-cache',
  'X-Forwarded-For': '81.2.69.142',
  'CF-IPCountry': 'GB',
  'X-Real-IP': '81.2.69.142'
};

// ---- Extract promo headings from page HTML ----
function extractPromos(pageHtml) {
  let clean = pageHtml
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '');

  const titles = new Set();
  const re = /<h[2-4][^>]*>([^<]{5,120})<\/h[2-4]>/gi;
  let m;
  while ((m = re.exec(clean)) !== null) {
    const t = m[1]
      .replace(/&amp;/g, '&')
      .replace(/&#39;/g, "'")
      .replace(/&quot;/g, '"')
      .replace(/&pound;/g, '£')
      .replace(/&#163;/g, '£')
      .replace(/\s+/g, ' ')
      .trim();
    if (t.length >= 8 && t.length <= 100 && /[a-zA-Z]/.test(t)) {
      titles.add(t);
    }
  }
  return [...titles].slice(0, 30);
}

// ---- Process a single brand ----
async function processBrand(brand) {
  try {
    let response;
    try {
      response = await $helpers.httpRequest({
        method: 'GET',
        url: brand.url,
        headers: UK_HEADERS,
        timeout: 10000,
        followRedirects: true,
        ignoreHttpStatusErrors: true,
        returnFullResponse: true
      });
    } catch (fetchErr) {
      brand.lastChecked = today;
      return;
    }

    const statusCode = response.statusCode || response.status || 200;
    const pageHtml = (typeof response.body === 'string') ? response.body : JSON.stringify(response.body || '');

    const geoBlocked = [
      'prohibited location', 'not available in your region',
      'access denied', 'not available in your country',
      'region is not supported', 'country is not supported'
    ].some(p => pageHtml.toLowerCase().includes(p));

    if (statusCode >= 400 || pageHtml.length < 800 || geoBlocked) {
      brand.lastChecked = today;
      return;
    }

    const newPromos = extractPromos(pageHtml);
    if (newPromos.length < 2) {
      brand.lastChecked = today;
      return;
    }

    const normalize = s => s.toLowerCase().replace(/[^a-z0-9]/g, '');
    const storedNorm = (brand.promos || []).map(normalize);
    const newNorm = newPromos.map(normalize);

    const hasNew = newNorm.some(n =>
      !storedNorm.some(s => {
        const len = Math.min(n.length, s.length, 15);
        return len > 5 && n.slice(0, len) === s.slice(0, len);
      })
    );
    const hasRemoved = storedNorm.some(s =>
      !newNorm.some(n => {
        const len = Math.min(n.length, s.length, 15);
        return len > 5 && n.slice(0, len) === s.slice(0, len);
      })
    );

    brand.changed = hasNew || hasRemoved;
    brand.lastChecked = today;
    if (brand.changed) {
      brand.promos = newPromos;
    }
  } catch (e) {
    brand.lastChecked = today;
  }
}

// ---- Process brands in parallel batches of 5 ----
const BATCH_SIZE = 5;
for (let i = 0; i < brands.length; i += BATCH_SIZE) {
  await Promise.allSettled(brands.slice(i, i + BATCH_SIZE).map(processBrand));
}

// ---- Rebuild BRANDS array in HTML ----
const brandsStr = brands.map(b =>
  `  { name:${JSON.stringify(b.name)}, url:${JSON.stringify(b.url)}, lastChecked:${JSON.stringify(b.lastChecked)}, changed:${b.changed}, promos:${JSON.stringify(b.promos)} }`
).join(',\n');

const updatedHtml = html.slice(0, brandsStart) +
  'const BRANDS = [\n' + brandsStr + '\n]' +
  html.slice(brandsEnd);

// Re-encode for GitHub API
const updatedContent = Buffer.from(updatedHtml).toString('base64');

return [{
  json: {
    content: updatedContent,
    sha: sha,
    message: `Dashboard update via n8n \u2013 ${today}`
  }
}];
